import torch
import pickle
from typing import Dict, Any, Tuple


class RestrictedUnpickler(pickle.Unpickler):
    """Restricted unpickler to prevent arbitrary code execution."""
    ALLOWED_CLASSES = {
        # Torch core types
        ('torch', 'Tensor'),
        ('torch.nn.parameter', 'Parameter'),
        # Basic Python types
        ('builtins', 'dict'),
        ('builtins', 'list'),
        ('builtins', 'tuple'),
        ('builtins', 'int'),
        ('builtins', 'float'),
        ('builtins', 'bool'),
        ('builtins', 'str'),
        # Compatibility with older Python versions
        ('__builtin__', 'dict'),
        ('__builtin__', 'list'),
        ('__builtin__', 'tuple'),
        ('__builtin__', 'int'),
        ('__builtin__', 'float'),
        ('__builtin__', 'bool'),
        ('__builtin__', 'str'),
    }

    def find_class(self, module: str, name: str) -> Any:
        if (module, name) in self.ALLOWED_CLASSES:
            return super().find_class(module, name)
        raise pickle.UnpicklingError(f"Disallowed class {module}.{name} detected in checkpoint.")


def _move_to_cpu(obj: Any) -> Any:
    """Recursively move all tensors in an object to CPU."""
    if isinstance(obj, torch.Tensor):
        return obj.to("cpu")
    elif isinstance(obj, dict):
        return {k: _move_to_cpu(v) for k, v in obj.items()}
    elif isinstance(obj, list):
        return [_move_to_cpu(i) for i in obj]
    elif isinstance(obj, tuple):
        return tuple(_move_to_cpu(i) for i in obj)
    else:
        return obj


def resume_training_from_checkpoint(checkpoint_path: str) -> Dict[str, Any]:
    """
    Load a training checkpoint from the specified path and return its contents.

    Args:
        checkpoint_path: Path to the checkpoint file (.ckpt or .pth)

    Returns:
        Dictionary containing either the raw model state dict or a full checkpoint with
        model_state_dict, optimizer_state_dict, and training_metadata keys.

    Raises:
        FileNotFoundError: If the checkpoint file does not exist
        PermissionError: If there is no read access to the checkpoint file
        RuntimeError: If the checkpoint is corrupted or not a valid PyTorch file
        TypeError: If the loaded data is not a dictionary
        ValueError: If the checkpoint is missing required components for resuming training
    """
    try:
        # First try safe loading with weights_only=True (tensors only)
        checkpoint_data = torch.load(
            checkpoint_path,
            weights_only=True,
            map_location="cpu"
        )
    except RuntimeError:
        # Fallback to restricted unpickling for checkpoints with non-tensor data
        try:
            with open(checkpoint_path, 'rb') as f:
                unpickler = RestrictedUnpickler(f)
                checkpoint_data = unpickler.load()
                checkpoint_data = _move_to_cpu(checkpoint_data)
        except Exception as e:
            raise RuntimeError(
                f"Failed to load checkpoint with restricted unpickling. Details: {str(e)}"
            ) from e
    except FileNotFoundError:
        raise FileNotFoundError(f"Checkpoint file not found at path: {checkpoint_path}")
    except PermissionError:
        raise PermissionError(f"Permission denied when accessing checkpoint file: {checkpoint_path}")
    except Exception as e:
        raise RuntimeError(f"Unexpected error loading checkpoint: {str(e)}") from e

    # Validate checkpoint structure
    if not isinstance(checkpoint_data, dict):
        raise TypeError(f"Expected checkpoint to be a dictionary, got {type(checkpoint_data).__name__}")

    # Verify required components exist if it's a full checkpoint
    if "model_state_dict" in checkpoint_data:
        required_keys = {"model_state_dict", "optimizer_state_dict"}
        missing_keys = required_keys - checkpoint_data.keys()
        if missing_keys:
            raise ValueError(
                f"Checkpoint is missing required components for resuming training: {', '.join(missing_keys)}"
            )

    return checkpoint_data

